// Parse Typeform webhook payload
const webhookData = $input.first().json;
const formResponse = webhookData.form_response || webhookData;

// Extract answers from Typeform
const answers = {};
if (formResponse.answers) {
  formResponse.answers.forEach(answer => {
    const fieldRef = answer.field?.ref || answer.field?.id || '';
    if (answer.type === 'email') answers.email = answer.email || '';
    else if (answer.type === 'text') answers[fieldRef] = answer.text || '';
    else if (answer.type === 'long_text') answers[fieldRef] = answer.text || '';
    else if (answer.type === 'choice') answers[fieldRef] = answer.choice?.label || '';
    else if (answer.type === 'choices') answers[fieldRef] = answer.choices?.labels || [];
    else if (answer.type === 'number') answers[fieldRef] = parseInt(answer.number || 0);
  });
}

// Map Typeform answers to consultation data
const consultationData = {
  // Basic info
  name: answers.name || answers.Name || answers['full-name'] || '',
  email: answers.email || answers.Email || '',
  phone: answers.phone || answers.Phone || answers['phone-number'] || '',

  // Business info
  businessType: answers.business_type || answers['business-type'] || answers.businessType || '',
  businessName: answers.business_name || answers['business-name'] || '',
  teamSize: parseInt(answers.team_size || answers['team-size'] || 0),
  monthlyRevenue: answers.monthly_revenue || answers['monthly-revenue'] || '',

  // Consultation questions
  currentChallenges: answers.challenges || answers.current_challenges || answers['current-challenges'] || '',
  automationGoals: answers.goals || answers.automation_goals || answers['automation-goals'] || '',
  budget: answers.budget || answers.Budget || '',
  timeline: answers.timeline || answers.Timeline || '',

  // Additional context
  currentTools: Array.isArray(answers.current_tools || answers['current-tools']) ? answers.current_tools || answers['current-tools'] : [],
  topPriority: answers.top_priority || answers['top-priority'] || '',

  // Metadata
  formId: webhookData.form_id || '',
  submittedAt: formResponse.submitted_at || new Date().toISOString(),
  sessionId: `voice-ai-${Date.now()}`
};

// Generate consultation context for Voice AI
const voiceAIContext = `
Consultation Context for Voice AI Agent:

Customer Information:
- Name: ${consultationData.name}
- Email: ${consultationData.email}
- Phone: ${consultationData.phone}
- Business: ${consultationData.businessName || consultationData.businessType}
- Team Size: ${consultationData.teamSize}
- Monthly Revenue: ${consultationData.monthlyRevenue}

Current Situation:
- Challenges: ${consultationData.currentChallenges}
- Current Tools: ${consultationData.currentTools.join(', ') || 'None specified'}

Goals:
- Automation Goals: ${consultationData.automationGoals}
- Top Priority: ${consultationData.topPriority}

Budget & Timeline:
- Budget: ${consultationData.budget}
- Timeline: ${consultationData.timeline}

Instructions for Voice AI Agent:
1. Use this context to personalize the consultation
2. Reference specific challenges mentioned: ${consultationData.currentChallenges}
3. Focus on their top priority: ${consultationData.topPriority}
4. Respect their budget range: ${consultationData.budget}
5. Work within their timeline: ${consultationData.timeline}
6. Ask clarifying questions based on their current tools: ${consultationData.currentTools.join(', ') || 'Ask what tools they use'}
`;

return [{
  json: {
    success: true,
    consultationData: consultationData,
    voiceAIContext: voiceAIContext,
    sessionId: consultationData.sessionId
  }
}];
